import { Service } from "./service";

class App {
    constructor (){
        var service = new Service();  

        // listenner go to top page
        document.getElementById("go-up").onclick = function() {service.scrollToUp()};

        var selectors = document.getElementsByName("selector");

        selectors.forEach(selector=> {
            selector.addEventListener("change", function() {
                switch(selector.id) {
                    case "option-1":
                        service.option1 = selector.value;
                        break;
                    case "option-2":
                        service.option2 = selector.value;
                        break;
                    case "option-3":
                        service.option3 = selector.value;
                        break;
                }
                
                if (service.option1 && service.option2 && service.option3) {
                    let itemsOutput = document.getElementsByClassName("items-output")[0];
                    
                    service.showLoader();
                    service.scrollToDown();
                    service.hideTextResults();
                    service.hideItems();

                    while (itemsOutput.firstChild) {
                        itemsOutput.firstChild.remove()
                    }
                    
                    service.getGreenThumb(service.option1, service.option2, service.option3).then(items => {
                        // sort to staff true
                        items.sort((a,b) => a.staff_favorite ? -1 : 1);

                        items.forEach(item=> {
                            let newItem = service.createItem(item.id, item.name, item.sun, item.water, item.url, item.price, item.toxicity, item.staff_favorite);
                            itemsOutput.appendChild(newItem);
                        });
                        
                        service.hideLoader();
                        service.hideTextResults();
                        service.showItems();
                        service.scrollToDown();
                        
                    }).catch(e=> {
                        // some request gime us 404.. not found..
                        service.scrollToUp();
                        service.showTextResults();
                        service.hideLoader();
                        service.hideItems();

                    })
                    
                }

            });
        });
    }
    
}

// call application when document is complete
var loaderInvterval = setInterval(()=>{
    if (document.readyState === "complete") {
        clearInterval(loaderInvterval);
        new App();
    }
},100);
